import games from "@/data/games.json";

export type Game = {
  id: string;
  title: string;
  acceptableAnswers?: string[];
  images: string[];
};

export type DailyGame = Game & {
  puzzleKey: string; // YYYY-MM-DD (UTC)
  maxGuesses: number;
};

function toPuzzleKeyUTC(d: Date) {
  return d.toISOString().slice(0, 10);
}

function dayIndexUTC(d: Date) {
  const year = d.getUTCFullYear();
  const start = Date.UTC(year, 0, 1);
  const today = Date.UTC(year, d.getUTCMonth(), d.getUTCDate());
  return Math.floor((today - start) / (24 * 60 * 60 * 1000));
}

export function getDailyGame(date = new Date()): DailyGame {
  const list = games as Game[];
  if (!list.length) {
    throw new Error("data/games.json 为空：请先添加至少 1 个游戏条目。");
  }

  const idx = dayIndexUTC(date) % list.length;
  const g = list[idx]!;
  return {
    ...g,
    puzzleKey: toPuzzleKeyUTC(date),
    maxGuesses: 6,
  };
}

export function getGameById(id: string): Game | undefined {
  const list = games as Game[];
  return list.find((g) => g.id === id);
}

export function normalizeAnswer(s: string) {
  return s
    .toLowerCase()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, "");
}

